class SafeObjectInputStream extends ObjectInputStream {
    private final Set<String> allowedClasses;
    
    public SafeObjectInputStream(InputStream in, Set<String> allowedClasses) throws IOException {
        super(in);
        this.allowedClasses = allowedClasses;
    }
    
    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) throws IOException, ClassNotFoundException {
        String className = desc.getName();
        
        if (!isAllowedClass(className)) {
            throw new InvalidClassException("Unauthorized deserialization attempt: " + className);
        }
        
        return super.resolveClass(desc);
    }
    
    private boolean isAllowedClass(String className) {
        if (className.startsWith("java.lang.") || 
            className.startsWith("java.util.") ||
            className.equals("[B") ||
            className.equals("[I") ||
            className.equals("[J") ||
            className.equals("[D") ||
            className.equals("[F") ||
            className.equals("[Z") ||
            className.equals("[C") ||
            className.equals("[S")) {
            return true;
        }
        
        for (String allowed : allowedClasses) {
            if (className.equals(allowed) || className.startsWith(allowed + "$")) {
                return true;
            }
        }
        
        return false;
    }
}

